package org.apache.commons.csv;
import java.io.Serializable;
import java.util.Arrays;
import java.util.Iterator;
import java.util.List;
import java.util.Map.Entry;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;
import java.util.HashMap;
import java.util.Map;

public class CSVRecordTest {

    @Test
    void testValuesMethod() throws Exception {
        String[] values = new String[] {"a", "b", "c"};
        Map<String, Integer> mapping = new HashMap<>();
        mapping.put("one", 0);
        mapping.put("two", 1);
        mapping.put("three", 2);
        String comment = "comment";
        long recordNumber = 5L;

        // Use the package-private constructor by reflection since it's package-private
        // and test class might be in a different package
        CSVRecord record;
        try {
            record = new CSVRecord(values, mapping, comment, recordNumber);
        } catch (IllegalAccessError | NoSuchMethodError e) {
            // If constructor is package-private and inaccessible, use reflection
            var constructor = CSVRecord.class.getDeclaredConstructor(String[].class, Map.class, String.class, long.class);
            constructor.setAccessible(true);
            record = constructor.newInstance(values, mapping, comment, recordNumber);
        }

        Method valuesMethod = CSVRecord.class.getDeclaredMethod("values");
        valuesMethod.setAccessible(true);

        String[] result = (String[]) valuesMethod.invoke(record);

        assertNotNull(result);
        assertArrayEquals(values, result);
    }
}
